# 种类并查集
代码
~~~
#include <iostream>
#define endl "\n"
using namespace std;
typedef long long ll;
const int maxn = 1e6 + 7;
const int inf = 2147483647;
int fa[maxn];
int find(int x)
{
    return x == fa[x] ? x : fa[x] = find(fa[x]);
}
void merge(int x, int y)
{
    x = find(x), y = find(y);
    if (x != y) fa[x] = y; //x 指向y，表示x和y为同一级（同类）
}
void solve()
{
    int n, k, ans = 0;
    scanf("%d %d", &n, &k);
    for (int i = 1; i <= 3 * n; i++) fa[i] = i;
    // 1 -- n x同类
    // n + 1 -- 2 * n x可以吃
    // 2 * n + 1 -- 3 * n x天敌
    while (k--)
    {
        int op, x, y;
        scanf("%d %d %d", &op, &x, &y);
        if (x > n || y > n) { ans++; continue; }

        if (op == 1){
            if (find(x) == find(y + n) || find(x) == find(y + 2 * n)){ans++; continue;}
            //如果1是2的天敌或猎物，显然为谎言
			else merge(x, y), merge(x + n, y + n), merge(x + 2 * n, y + 2 * n);
			//如果为真，那么1的同类和2的同类，1的猎物是2的猎物，1的天敌是2的天敌
		}
        else{
            if (x == y) { ans++; continue; }
			if (find(x + 2 * n) == find(y) || find(x) == find(y)) {ans++; continue;}
            //如果1是2的同类或猎物，显然为谎言
			else{
                merge(y, x + n),merge(x, y + 2 * n),merge(x + 2 * n,  y + n);
				//如果为真，那么1的同类是2的天敌，1的猎物是2的同类，1的天敌是2的猎物
			}
        }

    }
    printf("%d\n", ans);
}
signed main()
{
    int t = 1;
    while (t--)
    {
        solve();
    }
    return 0;
}
