        if (j < v[x])  
        {  
            sum = dfs(x + 1, j);  
        }  
        else  
        {  
            sum = max(dfs(x + 1, j), dfs(x + 1,j - v[x]) + w[x]);  
        }  
    }  
    mem[x][j] = sum;  
    return sum;  
}
~~~

