# 多重背包问题II
把个数转为二进制来解决, 降低时间复杂度
```
#include<bits/stdc++.h>
using namespace std;
const int N = 2005;

int f[N];
int n, m;

struct goods {
    int v, w;
};

vector<goods> good;
int main()
{

	ios::sync_with_stdio(0);
	cin.tie(0);
	cout.tie(0) ;

	cin >> n >> m;

	for (int i = 1; i <= n; ++i)  {

	    int va, wi, s;
	    cin >> va >> wi >> s;

	    for (int k = 1; k <= s; k *= 2) {

	        s -= k;
	        good.push_back({va * k, wi * k});
	    }

	    if (s) good.push_back({va * s, wi * s});
	}

	for (auto it : good) 
	for (int j = m; j >= it.v; --j) {

	    f[j] = max(f[j], f[j - it.v] + it.w);
	}

    cout << f[m];
	return 0;
 } 
```

