应用前缀和的思想
在（x1， y1）出加上c，
然后（x1， y2 + 1） - c ， （x2 + 1， y1） - c 和 （x2 + 1， y2 + 1）+c， 加上重复部分
![[Pasted image 20241030090742.png]]


~~~
#include<iostream>
#include<cstdio>
using namespace std;
const int N = 1e3 + 10;
int a[N][N], b[N][N];
void insert(int x1, int y1, int x2, int y2, int c)
{
    b[x1][y1] += c; // （x1， y1）以后的部分加c
    b[x2 + 1][y1] -= c;//（x1， y2 + 1） 后面的部分恢复原数
    b[x1][y2 + 1] -= c; //（x2， y1） 后面的部分恢复原数
    b[x2 + 1][y2 + 1] += c; //加上重复减去的数
}
int main()
{
    int n, m, q;
    cin >> n >> m >> q;
    for (int i = 1; i <= n; i++)
        for (int j = 1; j <= m; j++)
            cin >> a[i][j];
    for (int i = 1; i <= n; i++)
    {
        for (int j = 1; j <= m; j++)
        {
            insert(i, j, i, j, a[i][j]);      //构建差分数组
        }
    }
    while (q--)
    {
        int x1, y1, x2, y2, c;
        cin >> x1 >> y1 >> x2 >> y2 >> c;
        insert(x1, y1, x2, y2, c);
    }
    for (int i = 1; i <= n; i++)
    {
        for (int j = 1; j <= m; j++)
        {
            b[i][j] += b[i - 1][j] + b[i][j - 1] - b[i - 1][j - 1];  //二维前缀和
        }
    }
    for (int i = 1; i <= n; i++)
    {
        for (int j = 1; j <= m; j++)
        {
            printf("%d ", b[i][j]);
        }
        printf("\n");
    }
    return 0;
}

